// src/services/dbSimulador.js
export const dbSimulador = {
  getOfertasGlobales: () => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let todas = [];

    locales.forEach(local => {
      const ofertas = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      todas = [...todas, ...ofertas.map(o => ({
        ...o,
        localId: local.id,
        nombreLocal: local.nombre,
        direccionLocal: local.direccion,
        provincia: local.provincia, // Ahora viene del modal
        ciudad: local.ciudad,       // Ahora viene del modal
        zona: local.zona,           // Ahora viene del modal
        coords: local.coords
      }))];
    });
    return todas;
  },
  
  publicarOferta: (idLocal, oferta) => {
    const clave = `ofertas-local-${idLocal}`;
    const existentes = JSON.parse(localStorage.getItem(clave) || "[]");
    const nueva = { 
      ...oferta, 
      id: Date.now(), 
      localId: idLocal,
      precioNuevo: parseFloat(oferta.precioNuevo),
      precioViejo: parseFloat(oferta.precioViejo)
    };
    localStorage.setItem(clave, JSON.stringify([...existentes, nueva]));
    return nueva;
  }
};
